import React, { useEffect, useState, useCallback } from 'react';
import { useTable, useSortBy, usePagination } from 'react-table';
import './PurchaseFunc.css';

const ProjectOutflows = ({ apiBaseUrl, userRole }) => {
    const [projectId, setProjectId] = useState(null);
    const [projects, setProjects] = useState([]);
    const [outflows, setOutflows] = useState([]);
    const [laborHours, setLaborHours] = useState([]);
    const [isLoading, setIsLoading] = useState(true);
    const [employees, setEmployees] = useState([]);
    const [materials, setMaterials] = useState([]);
    const [purchases, setPurchases] = useState([]);

    useEffect(() => {
        const params = new URLSearchParams(window.location.search);
        const projectIdParam = params.get('projectId');

        if (projectIdParam) {
            setProjectId(projectIdParam);
        }
    }, []);

    const fetchAPI = useCallback(async (url, options = {}) => {
        const authToken = sessionStorage.getItem('authToken');
        const response = await fetch(url, {
            ...options,
            headers: {
                ...options.headers,
                'Authorization': `Bearer ${authToken}`,
                'Content-Type': 'application/json',
            },
        });
        if (!response.ok) {
            const errorResponse = await response.json();
            throw new Error(errorResponse.message || `Error fetching ${url}`);
        }
        return response.json();
    }, []);

    const fetchData = useCallback(async () => {
        if (!projectId) return;

        setIsLoading(true);

        try {
            const [outflowsResponse, projectsResponse, employeesResponse, materialsResponse, purchaseResponse, laborHoursResponse] = await Promise.all([
                fetchAPI(`${apiBaseUrl}/outflowsAPI`),
                fetchAPI(`${apiBaseUrl}/projectsAPI`),
                fetchAPI(`${apiBaseUrl}/employeesAPI`),
                fetchAPI(`${apiBaseUrl}/materiallist`),
                fetchAPI(`${apiBaseUrl}/PurchasesAPI`),
                fetchAPI(`${apiBaseUrl}/laborHoursAPI`),
            ]);

            setOutflows(outflowsResponse.filter(res => res.project === parseInt(projectId)));
            setLaborHours(laborHoursResponse.filter(res => res.projectid === parseInt(projectId)));
            setEmployees(employeesResponse);
            setProjects(projectsResponse);
            setMaterials(materialsResponse);
            setPurchases(purchaseResponse);
        } catch (error) {
            console.log('Error fetching data:', error);
        } finally {
            setIsLoading(false);
        }
    }, [projectId, apiBaseUrl, fetchAPI]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const calculateTotalCost = (data, costKey) => {
        return data.reduce((total, item) => total + (parseFloat(item[costKey]) || 0), 0).toFixed(2);
    };

    const outflowColumns = [
        { Header: 'ID', accessor: 'outflowid' },
        { Header: 'Date', accessor: 'date' },
        { Header: 'Material ID', accessor: 'materialid' },
        { Header: 'Quantity', accessor: 'quantity' },
    ];

    const laborColumns = [
        { Header: 'ID', accessor: 'labid' },
        { Header: 'Date', accessor: 'date' },
        { Header: 'Employee', accessor: 'employeeid' },
        { Header: 'Hours Worked', accessor: 'hoursWorked' },
    ];

    if (userRole !== 'Senior') {
        outflowColumns.push({
            Header: 'Material Cost',
            accessor: 'cost',
            Cell: ({ value }) => `${value.toFixed(2)} €`,
        });

        laborColumns.push({
            Header: 'Labor Cost',
            accessor: 'cost_of_labor',
            Cell: ({ value }) => `${value.toFixed(2)} €`,
        });
    }

    const totalMaterialCost = userRole !== 'Senior' ? calculateTotalCost(outflows, 'cost') : null;
    const totalLaborCost = userRole !== 'Senior' ? calculateTotalCost(laborHours, 'cost_of_labor') : null;
    const totalCost = userRole !== 'Senior' ? (parseFloat(totalMaterialCost) + parseFloat(totalLaborCost)).toFixed(2) : null;

    if (isLoading) {
        return <div>Loading...</div>;
    }

    return (
        <div className="container">
            <h1>Project Outflows</h1>
            <table className="table">
                <thead>
                    <tr>
                        {outflowColumns.map(column => (
                            <th key={column.Header}>{column.Header}</th>
                        ))}
                    </tr>
                </thead>
                <tbody>
                    {outflows.map(row => (
                        <tr key={row.outflowid}>
                            {outflowColumns.map(column => (
                                <td key={column.Header}>{row[column.accessor]}</td>
                            ))}
                        </tr>
                    ))}
                </tbody>
            </table>

            {userRole !== 'Senior' && (
                <div>
                    <strong>Total Material Cost:</strong> {totalMaterialCost} €
                </div>
            )}

            <h2>Labor Hours</h2>
            <table className="table">
                <thead>
                    <tr>
                        {laborColumns.map(column => (
                            <th key={column.Header}>{column.Header}</th>
                        ))}
                    </tr>
                </thead>
                <tbody>
                    {laborHours.map(row => (
                        <tr key={row.labid}>
                            {laborColumns.map(column => (
                                <td key={column.Header}>{row[column.accessor]}</td>
                            ))}
                        </tr>
                    ))}
                </tbody>
            </table>

            {userRole !== 'Senior' && (
                <div>
                    <strong>Total Labor Cost:</strong> {totalLaborCost} €
                </div>
            )}

            {userRole !== 'Senior' && (
                <div>
                    <strong>Total Cost:</strong> {totalCost} €
                </div>
            )}
        </div>
    );
};

export default ProjectOutflows;
